#!/bin/bash
#
# Usage: update_tao_version.sh <version>

set -euo pipefail

VERSION="${1:?Usage: update_tao_version.sh <version>}"

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
VERSION_FILE="$REPO_ROOT/tao/version/tao_version_mod.f90"

cat >"$VERSION_FILE" <<EOF
!+
! Module tao_version_mod
!
! This file is generated by .github/scripts/update_tao_version.sh
! during the release workflow. Do not edit by hand.
!-

module tao_version_mod
character(*), parameter :: tao_version_date = "$VERSION"
end module
EOF

echo "Stamped $VERSION_FILE with version $VERSION"
